    "lyricsHtml": "\n[Intro]  <span class=\"chord\" data-chord=\"C\">C</span>  <span class=\"chord\" data-chord=\"G\">G</span>  <span class=\"chord\" data-chord=\"Dm\">Dm</span>  <span class=\"chord\" data-chord=\"F\">F</span>\n\n         <span class=\"chord\" data-chord=\"C\">C</span>      <span class=\"chord\" data-chord=\"G\">G</span>      <span class=\"chord\" data-chord=\"Dm\">Dm</span>      <span class=\"chord\" data-chord=\"F\">F</span>\n\n <span class=\"chord\" data-chord=\"C9\">C9</span>                   <span class=\"chord\" data-chord=\"G\">G</span>                <span class=\"chord\" data-chord=\"Dm\">Dm</span>       <span class=\"chord\" data-chord=\"F7\">F7</span>\n<span class=\"lyric-line\">Eu hoje tive um pesadelo e levantei atento, a tempo</span>\n<span class=\"chord\" data-chord=\"C9\">C9</span>                    <span class=\"chord\" data-chord=\"G\">G</span>\n<span class=\"lyric-line\">Eu acordei com medo e procurei no escuro</span>\n            <span class=\"chord\" data-chord=\"Dm\">Dm</span>                      <span class=\"chord\" data-chord=\"F7\">F7</span>\n<span class=\"lyric-line\">Alguém com seu carinho e lembrei de um tempo</span>\n<span class=\"chord\" data-chord=\"Am\">Am</span>                   <span class=\"chord\" data-chord=\"Am/G\">Am/G</span>\n<span class=\"lyric-line\">Porque o passado me traz uma lembrança</span>\n     <span class=\"chord\" data-chord=\"F7\">F7</span>               <span class=\"chord\" data-chord=\"F\">F</span>\n<span class=\"lyric-line\">Do tempo que eu era criança</span>\n<span class=\"chord\" data-chord=\"Am\">Am</span>               <span class=\"chord\" data-chord=\"Am/G\">Am/G</span>\n<span class=\"lyric-line\">E o medo era motivo de chôro</span>\n   <span class=\"chord\" data-chord=\"F7\">F7</span>                           <span class=\"chord\" data-chord=\"G\">G</span>\n<span class=\"lyric-line\">Desculpa para um abraço ou consolo</span>\n\n( <span class=\"chord\" data-chord=\"C\">C</span>  <span class=\"chord\" data-chord=\"G\">G</span>  <span class=\"chord\" data-chord=\"Dm\">Dm</span>  <span class=\"chord\" data-chord=\"F\">F</span> )\n\n<span class=\"chord\" data-chord=\"C9\">C9</span>                    <span class=\"chord\" data-chord=\"G\">G</span>               <span class=\"chord\" data-chord=\"Dm\">Dm</span>\n<span class=\"lyric-line\">Hoje eu acordei com medo, mas não chorei</span>\n                <span class=\"chord\" data-chord=\"F7\">F7</span>\n<span class=\"lyric-line\">Nem reclamei abrigo</span>\n<span class=\"chord\" data-chord=\"C9\">C9</span>                      <span class=\"chord\" data-chord=\"G\">G</span>             <span class=\"chord\" data-chord=\"Dm\">Dm</span>\n<span class=\"lyric-line\">Do escuro eu via um infinito sem presente</span>\n              <span class=\"chord\" data-chord=\"F7\">F7</span>\n<span class=\"lyric-line\">Passado ou futuro</span>\n<span class=\"chord\" data-chord=\"C9\">C9</span>                <span class=\"chord\" data-chord=\"G\">G</span>                <span class=\"chord\" data-chord=\"Dm\">Dm</span>\n<span class=\"lyric-line\">Senti um abraço forte, já não era medo</span>\n                         <span class=\"chord\" data-chord=\"F7+\">F7+</span>\n<span class=\"lyric-line\">Era uma coisa sua que ficou em mim (que não tem fim)</span>\n<span class=\"chord\" data-chord=\"F\">F</span>                   <span class=\"chord\" data-chord=\"G\">G</span>\n<span class=\"lyric-line\">De repente a gente vê que perdeu</span>\n      <span class=\"chord\" data-chord=\"Am\">Am</span>                  <span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Ou está perdendo alguma coisa</span>\n <span class=\"chord\" data-chord=\"F\">F</span>              <span class=\"chord\" data-chord=\"G\">G</span>\n<span class=\"lyric-line\">Morna e ingênua</span>\n                      <span class=\"chord\" data-chord=\"Am\">Am</span>\n<span class=\"lyric-line\">Que vai ficando no caminho</span>\n<span class=\"chord\" data-chord=\"F\">F</span>                <span class=\"chord\" data-chord=\"G\">G</span>                 <span class=\"chord\" data-chord=\"Am\">Am</span>\n<span class=\"lyric-line\">Que é escuro e frio, mas também bonito</span>\n               <span class=\"chord\" data-chord=\"D\">D</span>\n<span class=\"lyric-line\">Porque é iluminado</span>\n      <span class=\"chord\" data-chord=\"F\">F</span>                   <span class=\"chord\" data-chord=\"G\">G</span>\n<span class=\"lyric-line\">Pela beleza do que aconteceu</span>\n              <span class=\"chord\" data-chord=\"C\">C</span>\n<span class=\"lyric-line\">A minutos atrás</span>\n",
